"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[9371],{2427:(e,i,n)=>{n.r(i),n.d(i,{data:()=>s});const s={key:"v-691d8675",path:"/C#/WCF.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"WCF",slug:"wcf",children:[{level:3,title:"简介",slug:"简介",children:[]},{level:3,title:"创建WCF服务",slug:"创建wcf服务",children:[]},{level:3,title:"测试服务",slug:"测试服务",children:[]},{level:3,title:"使用http访问",slug:"使用http访问",children:[]}]}],git:{updatedTime:1656031417e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:3}]},filePathRelative:"C#/WCF.md"}},44249:(e,i,n)=>{n.r(i),n.d(i,{default:()=>l});const s=(0,n(57293).uE)('<h2 id="wcf" tabindex="-1"><a class="header-anchor" href="#wcf" aria-hidden="true">#</a> WCF</h2><h3 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h3><p>Windows Communication Foundation (WCF) 是一个框架，用于生成面向服务的应用程序。它取代了较旧的进程间通信技术，例如 ASMX Web 服务、.NET 远程处理、企业服务 (DCOM) 和 MSMQ。 WCF 将所有这些技术的功能汇集在一个统一的编程模型下，简化了开发分散式应用程序的体验。 使用 WCF，可以将数据作为异步消息从一个服务终结点发送到另一个服务终结点。 服务终结点可以是由 IIS 承载的持续可用的服务的一部分，也可以是应用程序中承载的服务。 终结点可以是从服务终结点请求数据的服务客户端。 简单消息可以是作为 XML 发送的单个字符或单个单词，复杂消息可以是二进制数据流。</p><h3 id="创建wcf服务" tabindex="-1"><a class="header-anchor" href="#创建wcf服务" aria-hidden="true">#</a> 创建WCF服务</h3><p>如果发现找不到wcf项目，这时你需要去安装Visual Studio 的<strong>Windows Communication Foundation</strong>组件</p><p>1.创建过程如下</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210911173.png" alt="1625557744199"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210911175.png" alt="1625560968492"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210911176.png" alt="1625561024155"></p><p>2.项目创建成功后，会自动生成的一些演示文件</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210911176.png" alt="1625561055185"></p><p>IService1.cs</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>namespace WcfService1\n{\n    // 注意: 使用“重构”菜单上的“重命名”命令，可以同时更改代码和配置文件中的接口名“IService1”。\n    [ServiceContract]\n    public interface IService1\n    {\n\n        [OperationContract]\n        string GetData(int value);\n\n        [OperationContract]\n        CompositeType GetDataUsingDataContract(CompositeType composite);\n\n        // TODO: 在此添加您的服务操作\n    }\n\n\n    // 使用下面示例中说明的数据约定将复合类型添加到服务操作。\n    [DataContract]\n    public class CompositeType\n    {\n        bool boolValue = true;\n        string stringValue = &quot;Hello &quot;;\n\n        [DataMember]\n        public bool BoolValue\n        {\n            get { return boolValue; }\n            set { boolValue = value; }\n        }\n\n        [DataMember]\n        public string StringValue\n        {\n            get { return stringValue; }\n            set { stringValue = value; }\n        }\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Service1.cs</p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>namespace WcfService1\n{\n    // 注意: 使用“重构”菜单上的“重命名”命令，可以同时更改代码、svc 和配置文件中的类名“Service1”。\n    // 注意: 为了启动 WCF 测试客户端以测试此服务，请在解决方案资源管理器中选择 Service1.svc 或 Service1.svc.cs，然后开始调试。\n    public class Service1 : IService1\n    {\n        public string GetData(int value)\n        {\n            return string.Format(&quot;You entered: {0}&quot;, value);\n        }\n\n        public CompositeType GetDataUsingDataContract(CompositeType composite)\n        {\n            if (composite == null)\n            {\n                throw new ArgumentNullException(&quot;composite&quot;);\n            }\n            if (composite.BoolValue)\n            {\n                composite.StringValue += &quot;Suffix&quot;;\n            }\n            return composite;\n        }\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="测试服务" tabindex="-1"><a class="header-anchor" href="#测试服务" aria-hidden="true">#</a> 测试服务</h3><p>按 F5 运行该服务。 WCF 测试客户端 窗体随即出现并加载服务。</p><p>在“WCF 测试客户端”窗体中，双击 IService1 下的 GetData() 方法。 此时会显示 &quot;工作&quot; 选项卡。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206230922517.png" alt="image-20220623092223470"></p><p>在“请求”框中，选择“值”字段，并键入 1314。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206230922377.png" alt="image-20220623092235342"></p><p>如上所示，我们的服务没有问题，然后在浏览器输入服务地址http://192.168.43.219/SchoolService(配置文件中的baseAddress)查看服务，我们可以点击查看服务的wsdl文档，wsdl详细展示了服务的方法、数据类型、服务地址等信息。</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206230922819.png" alt="image-20220623092243782"></p><h3 id="使用http访问" tabindex="-1"><a class="header-anchor" href="#使用http访问" aria-hidden="true">#</a> 使用http访问</h3><p>https://blog.csdn.net/xunbaogang/article/details/82388145</p><p>（1）给方法添加说明</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210911271.png" alt="1625561256753"></p><div class="language-c# ext-c# line-numbers-mode"><pre class="language-c#"><code>[WebGet(UriTemplate = &quot;/GetData/{value}&quot;, RequestFormat = WebMessageFormat.Json, ResponseFormat = WebMessageFormat.Json)]\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>（2）修改WebConfig，<code>system.serviceModel</code>节点</p><div class="language-xml ext-xml line-numbers-mode"><pre class="language-xml"><code>&lt;?xml version=&quot;1.0&quot; encoding=&quot;utf-8&quot;?&gt;\n&lt;configuration&gt;\n\n  &lt;appSettings&gt;\n    &lt;add key=&quot;aspnet:UseTaskFriendlySynchronizationContext&quot; value=&quot;true&quot; /&gt;\n  &lt;/appSettings&gt;\n  &lt;system.web&gt;\n    &lt;compilation debug=&quot;true&quot; targetFramework=&quot;4.7.2&quot; /&gt;\n    &lt;httpRuntime targetFramework=&quot;4.7.2&quot;/&gt;\n  &lt;/system.web&gt;\n  &lt;system.serviceModel&gt;\n\t  &lt;bindings&gt;\n\t\t  &lt;webHttpBinding&gt;\n\t\t\t  &lt;binding name=&quot;webBinding&quot;/&gt;\n\t\t  &lt;/webHttpBinding&gt;\n\t  &lt;/bindings&gt;\n\t  &lt;services&gt;\n\t\t  &lt;service name=&quot;WcfService1.Service1&quot; behaviorConfiguration=&quot;serviceBehavior&quot;&gt;\n\t\t\t  &lt;endpoint address=&quot;&quot; behaviorConfiguration=&quot;webBehavior&quot; binding=&quot;webHttpBinding&quot; bindingConfiguration=&quot;webBinding&quot; contract=&quot;WcfService1.IService1&quot;/&gt;\n\t\t  &lt;/service&gt;\n\t  &lt;/services&gt;\n    &lt;behaviors&gt;\n\t\t&lt;endpointBehaviors&gt;\n\t\t\t&lt;behavior name=&quot;webBehavior&quot;&gt;\n\t\t\t\t&lt;!--这里必须设置--&gt;\n\t\t\t\t&lt;webHttp/&gt;\n\t\t\t&lt;/behavior&gt;\n\t\t&lt;/endpointBehaviors&gt;\n\t\t&lt;serviceBehaviors&gt;\n\t\t\t&lt;behavior name=&quot;serviceBehavior&quot;&gt;\n\t\t\t\t&lt;!-- 为避免泄漏元数据信息，请在部署前将以下值设置为 false --&gt;\n\t\t\t\t&lt;serviceMetadata httpGetEnabled=&quot;true&quot;/&gt;\n\t\t\t\t&lt;!-- 要接收故障异常详细信息以进行调试，请将以下值设置为 true。在部署前设置为 false 以避免泄漏异常信息 --&gt;\n\t\t\t\t&lt;serviceDebug includeExceptionDetailInFaults=&quot;false&quot;/&gt;\n\t\t\t&lt;/behavior&gt;\n\t\t&lt;/serviceBehaviors&gt;\n    &lt;/behaviors&gt;\n    &lt;protocolMapping&gt;\n        &lt;add binding=&quot;basicHttpsBinding&quot; scheme=&quot;https&quot; /&gt;\n    &lt;/protocolMapping&gt;    \n    &lt;serviceHostingEnvironment aspNetCompatibilityEnabled=&quot;true&quot; multipleSiteBindingsEnabled=&quot;true&quot; /&gt;\n  &lt;/system.serviceModel&gt;\n  &lt;system.webServer&gt;\n    &lt;modules runAllManagedModulesForAllRequests=&quot;true&quot;/&gt;\n    &lt;!--\n        若要在调试过程中浏览 Web 应用程序根目录，请将下面的值设置为 True。\n        在部署之前将该值设置为 False 可避免泄露 Web 应用程序文件夹信息。\n      --&gt;\n    &lt;directoryBrowse enabled=&quot;true&quot;/&gt;\n  &lt;/system.webServer&gt;\n\n&lt;/configuration&gt;\n\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>（3）参数必须使用字符串类型</p><p>使用其他类型会报如下错误</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210911288.png" alt="1625561186720"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210911834.png" alt="1625562991753"></p><p>（4）访问结果</p>',35),t={},l=(0,n(63243).Z)(t,[["render",function(e,i){return s}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,s]of i)n[e]=s;return n}}}]);